var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"그레모리 씨, 저 당신을 좋아합니다!","JPN":"グレモリーさん！　私、あなたのことが好きです！","ENG":"Gremory, I love you!","TWN":"葛茉莉小姐，我喜歡你！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어머, 그래?","JPN":"あら、そう？","ENG":"Oh, is that so?","TWN":"哎呀，真的嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"그레모리 씨의 가게에 손님이 찾아오는 데엔 여러 이유가 있습니다.","JPN":"グレモリーさんのお店にお客様がやってくる理由は色々です。","ENG":"There are many reasons why customers come to Gremory's bar.","TWN":"來到葛茉莉酒吧的客人，各有各的理由。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"순수하게 칵테일의 향과 맛을 즐기러 오는 손님도, 귀여운 모모를 보고 싶어서 오는 손님도 계시지만…","JPN":"単純にカクテルの香りと味を楽しむために来るお客様も、可愛いモモと会うために来るお客様もいるんですけど……","ENG":"Some come just to enjoy the cocktails, while others come to see Momo's cuteness...","TWN":"有人純粹是為了雞尾酒的香氣與口感而來，也有人是想看看可愛的莫莫……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"매력적인 그레모리 씨의 관심을 얻으려고 찾아오는 손님도 계세요.","JPN":"魅力的なグレモリーさんの目を引くためにやってくるお客様もいるんです。","ENG":"However, some people come to get the attention of the charming Gremory.","TWN":"但也有客人，是為了得到迷人的葛茉莉小姐的關注而來。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"지금까진 다들 내기를 한판하고 나면 포기하게 되지만요.","JPN":"今まではみんな賭けをしたら諦めるようになるんですけど。","ENG":"But most of them give up after losing a challenge.","TWN":"只不過到目前為止，大家在打完一場賭之後就都放棄了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"…세 잔이라고요?","JPN":"……3杯？","ENG":"...Three drinks?","TWN":"……三杯嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"응, 네가 술을 세 잔 마시고도 맨정신으로 버틸 수 있으면 내기에 이기는 거야.","JPN":"うん、アナタがお酒を3杯飲んでも酔っぱらっていないと、賭けで勝利するの。","ENG":"Yes, if you can still be sober after three drinks, then you win.","TWN":"嗯，只要你喝三杯還能保持清醒，就算你贏。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"정말이죠?! 그렇게만 하면 절 만나주시는 겁니까?","JPN":"本当ですよね！？　そしたら私と付き合ってくれるんですか？","ENG":"Really?! Then you'll go out with me?","TWN":"真的嗎？！只要那樣，你就願意跟我見面？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"고작 만나주는 정도로 만족하겠어? 해내기만 한다면 소원 하나 들어 줄게.","JPN":"付き合ってあげるだけで満足できる？　成功したら願いを1つ叶えてあげるわ。","ENG":"Will you be satisfied with just a date? If you win, I'll grant you a wish.","TWN":"只要見面你就滿足了？只要你辦得到，我都能幫你實現任何願望。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"무슨 소원이든 말이야.","JPN":"どんな願いでもね。","ENG":"Any wish your heart desires.","TWN":"不管是什麼願望哦。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"하겠습니다! 부디 하게 해주세요!","JPN":"やります！　どうかやらせてください！","ENG":"I'll do it! Please let me do it!","TWN":"我願意！請務必讓我試試看！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"들었지, 니콜 양? 데몬 레이디 세 잔 부탁해.","JPN":"聞いたわね、ニコルちゃん？　デーモンレディーを3杯お願い。","ENG":"Did you hear that, Nicole? Please prepare three glasses of Demon Lady.","TWN":"聽到了吧，妮可小姐？三杯惡魔淑女，拜託你了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네, 알겠습니다!","JPN":"はい、わかりました！","ENG":"Coming right up!","TWN":"是，我知道了！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"흐음, 향이 좋은데요? 이게 그레모리 씨가 평소 즐겨 마시는 칵테일이로군요.","JPN":"ふーん、いい香りですね。これがグレモリーさんがいつも飲んでいるカクテルですか？","ENG":"Hmm, it smells nice. So this is Gremory's favorite cocktail.","TWN":"嗯，香氣真好。原來這就是葛茉莉小姐平常喝的酒。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…조심하세요, 손님. 지금까지 데몬 레이디를 한 잔 이상 마시고 버틴 손님은 아무도 없었거든요.","JPN":"……気をつけてくださいね、お客様。今までデーモンレディーを1杯以上飲んで酔わなかったお客様は1人もいなかったんです。","ENG":"...Be careful, sir. No one has ever been able to finish more than one glass.","TWN":"……請小心，客人。到目前為止，沒有任何人能撐過第二杯惡魔淑女。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"하하, 괜찮아요. 난 술에 강하니까. 독해봤자 작은 잔에 담긴 칵테일일 뿐이죠.","JPN":"はは、大丈夫ですよ。私お酒には強いんで。これくらい小さなグラスの分では全然酔いませんから。","ENG":"Haha! Don't worry. I know how to hold my liquor. Plus, how strong can a cocktail be?","TWN":"哈哈，沒問題的。我酒量很好，再烈也不過是一小杯雞尾酒。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하아, 전 경고 드렸어요.","JPN":"はあ、私は警告しましたよ。","ENG":"*Sigh* You've been warned.","TWN":"唉，我可是警告過你了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"으… 음? 여긴 어디지?","JPN":"う……うん？　ここはどこだ？","ENG":"M-mm...? Where am I?","TWN":"呃……嗯？這裡是哪裡？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"손님아, 정신이 드느냐?","JPN":"客よ、目が覚めたか？","ENG":"Hey, you're finally awake.","TWN":"客人，你醒了嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"뿔 달린… 악마…?","JPN":"角の生えた……悪魔……？","ENG":"A devil... with horns...?","TWN":"長角的……惡魔……？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"정신이 든다면 17 곱하기 5의 정답을 말해보거라.","JPN":"目が覚めたなら、17かける5に答えるがよい。","ENG":"If you've come to your senses, tell me what 17 times 5 is.","TWN":"既然醒了，你說說看17乘以5等於多少。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"으음… 85…?","JPN":"うーん……85……？","ENG":"Um... 85...?","TWN":"嗯……85……？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"훌륭하도다. 정신이 돌아온 것을 칭찬하마.","JPN":"見事だ。意識を取り戻したことを褒めてやろう。","ENG":"Excellent. I praise you for coming to your senses.","TWN":"很好，恭喜你恢復意識了。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗! 모모! 숙제 문제 풀 때 손님한테 물어보지 말랬죠?","JPN":"あっ！　モモ！　宿題はお客様に聞かないでって言ったでしょう！","ENG":"Huh?! Momo! Didn't I tell you not to ask customers to help with your homework?","TWN":"啊！莫莫！寫作業的時候不可以問客人啦！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"니콜…? 제가 왜 여기에 누워있는 거죠?","JPN":"ニコル……？　どうして私がここで寝てるんですか？","ENG":"Nicole...? Why am I lying down here?","TWN":"妮可……？我怎麼會躺在這裡？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"첫 잔은 원샷이라면서 드시는 순간 쓰러지셨어요.","JPN":"最初の1杯は一気飲みだって飲んだ瞬間、倒れたんです。","ENG":"You fainted after shouting, \\"Bottoms up!\\" and guzzling down the first glass.","TWN":"你一口氣喝完第一杯後就倒下了。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"…그렇군요. 내 사랑은 고작 한 잔의 술 앞에 져버린 건가.","JPN":"……そうなんですか。私の恋はたかが1杯のお酒の前で負けてしまったのか。","ENG":"...I see. So my love's been lost to just one drink.","TWN":"……原來如此。我的愛情竟然輸給了一杯酒。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"너무 상심하지 마세요. 기회는 다음 번에도 있잖아요?","JPN":"あまりガッカリしないでくださいよ。チャンスはまたあるんですから。","ENG":"Don't be too upset. There's always next time, right?","TWN":"別太難過了，下次還有機會啊？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"아뇨. 괜찮습니다.","JPN":"いいえ。大丈夫です。","ENG":"No, that's all right.","TWN":"不了，沒關係。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"정신을 잃은 동안 제 지나온 삶을 보았거든요.","JPN":"気を失っていた間、私の今までの人生を見たんです。","ENG":"While I was out, I had time to reflect on my life.","TWN":"在失去意識的時候，我看見了人生跑馬燈。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"으음, 그걸 드신 분들은 다들 비슷한 경험을 하시더라고요.","JPN":"うーん、あれを飲んだ人たちはみんな似たような経験するんですよね。","ENG":"Mm, everyone who drank that cocktail seems to have had a similar experience.","TWN":"嗯，喝過這杯的人，幾乎都有類似的經驗。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"한 잔으로 과거를 돌이켜볼 수 있다니, 정말 굉장한 칵테일이네요.","JPN":"1杯で過去を振り返ってみることができるなんて、本当にすごいカクテルです。","ENG":"Being able to reflect on my past with just one glass. It really is an amazing cocktail.","TWN":"只要一杯酒就能回顧過去，真是了不起的雞尾酒。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아하하… 주마등은 엄청 위험한 전조라고 생각하는데요.","JPN":"あはは……走馬灯はとても危ない前兆だと思いますよ。","ENG":"Ah hah hah... Seeing your life flash before your eyes is an omen, if you ask me.","TWN":"啊哈哈……我反而覺得人生跑馬燈是很危險的前兆呢。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"내일 아침이 밝으면 바다로 여행이라도 떠나야겠어요.","JPN":"明日、夜が明けると海に旅行でも行きます。","ENG":"I think I'll go take a trip to the beach tomorrow morning.","TWN":"等明天早上天一亮，我打算去海邊旅行。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"사랑도 중요하지만… 나 스스로를 돌아보는 시간을 갖는 것도 좋겠죠.","JPN":"恋も大事ですけど……自分自身を振り返る時間を過ごすのもいいでしょうね。","ENG":"Love is important, but... I think it's also good to take time for myself to reflect.","TWN":"愛情固然很重要……但說不定花點時間重新審視自己也不錯。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"그럼, 언젠가 다시 만납시다. 니콜.","JPN":"では、いつかまた会いましょう。ニコル。","ENG":"Then, until we meet again, Nicole.","TWN":"那麼，妮可，以後再見吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네에…","JPN":"はい……","ENG":"Okay...","TWN":"嗯……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"아쉽구나. 항상 맛있는 과자를 잔뜩 사오는 손님이었는데 말이다.","JPN":"残念だ。いつも美味しいお菓子をたくさん買ってくる客だったのにな。","ENG":"What a shame. He used to bring a lot of tasty snacks every time he visited.","TWN":"真可惜，他每次都會買一大堆好吃餅乾來。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그러게요. 그레모리 씨의 내기에 진 손님들은 저렇게 떠나서 안 돌아오시니까요.","JPN":"そうですね。グレモリーさんとの賭けで負けたお客様って、みんなあれから帰ってこないですもんね。","ENG":"Yeah. All customers who lost to Gremory never come back.","TWN":"是啊，輸給葛茉莉小姐賭局的客人，通常就這樣離開、再也不回來了。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그렇지! 니콜이 그레모리에게 도전해보는 것은 어떠냐?","JPN":"そうだ！　ニコルがグレモリーに挑戦してみるのはどうだ？","ENG":"Oh! Why don't you challenge Gremory, Nicole?","TWN":"對了！妮可要不要也挑戰看看葛茉莉？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네? 제가요? 전 딱히 여자의 마음을 얻는다거나… 그렇고 그런 취향은 없는데요!?","JPN":"え？　私がですか？　私は別に女心を手に入れるとか……そんな趣味はないんですけど！？","ENG":"What? Me? But I'm not really interested in women... or anything like that!","TWN":"咦？我嗎？我對博取女性芳心之類的……完全沒有興趣啊？！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"내기에 이겨서 달콤한 걸 잔뜩 달라고 소원을 비는 것이다!","JPN":"賭けで勝利して、甘いものをたくさん買ってくれと願うのだ！","ENG":"You can wish for her to buy us tons of sweets after you win!","TWN":"許願要一大堆甜點當賭注就好啦！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아… 소원… 그런 게 있었죠.","JPN":"あ……願い……そんなものもありましたね。","ENG":"Oh, right... The wish...","TWN":"啊……許願……的確有這件事。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하지만 그레모리 씨가 저와의 내기를 받아주실까요?","JPN":"でも、グレモリーさんが私との賭けに応じてくれるんでしょうか？","ENG":"But do you think Gremory will accept my challenge?","TWN":"可是葛茉莉小姐會願意跟我賭嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"니콜 양은 안 돼. 나랑 내기하려면 우선 사랑에 빠져야 하거든.","JPN":"ニコルちゃんはダメ。アタシと賭けをするためには、まず恋に落ちていないと。","ENG":"Nicole doesn't qualify. Only those who've fallen in love with me can challenge me.","TWN":"不行喔，妮可小姐。要跟我賭，得先墜入愛河才行。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"기준이 모호하지 않나요?","JPN":"基準が曖昧じゃないですか？","ENG":"That's rather ambiguous.","TWN":"這標準不會太模糊了嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"솔직히 전혀 안 취하는 타입이라서 재미도 없고 말이야.","JPN":"正直、まったく酔わないタイプだから面白くないのよ。","ENG":"And honestly, it's no fun for me, because you don't get drunk at all.","TWN":"老實說，你完全喝不醉，一點都不好玩。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아하하…","JPN":"あはは……","ENG":"Ah hah hah...","TWN":"啊哈哈……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"게다가 두 사람은 내일 일찍 일어나봐야 하지 않아? 마감 정리는 내가 할게.","JPN":"それに二人は明日早いんじゃない？　アタシがお店閉めて片付けるわ。","ENG":"Plus, you two have to get up early tomorrow, right? Go. I'll finish up here.","TWN":"而且你們明天不是還要早起？我來就好。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…아 참! 제가 모모를 아카데미 입학식에 데려다 주기로 했었죠.","JPN":"……そうだ！　私がモモをアカデミーの入学式に連れて行くんでしたね。","ENG":"...Oh, right! I'm supposed to take Momo to her Academy entrance ceremony.","TWN":"……啊，對了！我答應要帶莫莫去學院開學典禮。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"모모 머리정돈 해준다는 걸 깜빡하고 있었네요.","JPN":"モモの髪の毛を整えるの、うっかり忘れてました。","ENG":"And I forgot to brush Momo's hair.","TWN":"差點忘了幫她梳頭髮。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"모모, 제 방으로 따라와요. 손톱 손질도 해줄게요.","JPN":"モモ、私の部屋に行きましょう。爪も手入れしてあげますよ。","ENG":"Momo, follow me to my room. I'll trim your fingernails for you too.","TWN":"莫莫，跟我來房間，我幫你剪指甲。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"싫어! 귀찮도다!","JPN":"嫌だ！　面倒なのだ！","ENG":"No! I don't want to!","TWN":"不要！麻煩死了！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"안 돼요. 제대로 관리도 안하고 가면 다른 친구들이 꾀죄죄한 모모를 흉볼 거라고요.","JPN":"ダメです。ちゃんと綺麗にしないと、他の友だちが薄汚いモモを見て悪口言うんです。","ENG":"No. Your friends will make fun of you if you look all scruffy, Momo.","TWN":"不行喔，不好好打理就去學校，其他孩子一定會說莫莫很邋遢。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"이 몸은 꾀죄죄하지 않아! 그런 말 하는 녀석들은 모두 하수인이 혼내 줄 것이니라!","JPN":"吾輩は薄汚くないぞ！　そんな話をするやつらはみんな下僕がこらしめるのだ！","ENG":"I am not scruffy! Anyone who says otherwise will be scolded by my subjects!","TWN":"我才不邋遢！說這種話的傢伙，全都都交給手下教訓！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"안 도와줄 건데?","JPN":"助けてあげないわよ？","ENG":"I'm not gonna help you.","TWN":"我可不幫忙喔？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"에…? 정말?!","JPN":"えっ……？　本当か！？","ENG":"Eh...? Really?!","TWN":"欸……真的嗎？！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L36_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"친구들은 혼내는 게 아니라 사이좋게 지내는 거야, 임금님. 그런 걸 배우라고 학교에 보내기로 한 거니까.","JPN":"友だちはこらしめるんじゃなくて仲良くするのよ、王様。そんなことを教わりなさいって学校に通わせるんだから。","ENG":"You're supposed to get along with your friends, not scold them, little majesty. That's why we're sending you to school.","TWN":"朋友不是用來教訓，是要好好相處的，國王。送你去學校就是為了學習這一點。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"들었죠? 그러니까 잔말 말고 얼른 따라와요.","JPN":"聞きましたね？　だからつべこべ言わないで早くついて来てください。","ENG":"You heard her. Now, stop whining and follow me.","TWN":"聽到了吧？所以別囉唆，快跟我來。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"흐에엑- 구, 구레나룻은 남겨주는 것이다.","JPN":"ほええっ……頬ひげは残してくれ。","ENG":"Heek! P-please leave my side bangs.","TWN":"嗚欸—鬢角要留下來啦。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"안 잘라요. 대체 그런 말은 어디서 배운 거예요?","JPN":"切りません。そんな言葉はいったいどこで覚えたんですか？","ENG":"I won't cut your hair. But where did you learn to say that?","TWN":"我不會剪的啦，你到底是從哪學來這種話的？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…영락없는 보모네.","JPN":"……もう完全に保母ね。","ENG":"...You are a true nanny.","TWN":"……完全就是保母呢。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"지금은 이 정도로 충분하려나?","JPN":"今はこれで十分かしら。","ENG":"Maybe this will be enough for now.","TWN":"現在這樣差不多了吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아직 영업 중인가?","JPN":"まだ営業中か？","ENG":"Are you open?","TWN":"還在營業嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"끝났다고 한들, 일부러 찾아와 준 손님을 어떻게 돌려보내겠어.","JPN":"終わったとしても、わざわざ来てくれたお客さんを帰らせるわけにはいかないわ。","ENG":"Even if we weren't, how can I just send away a customer who came all this way?","TWN":"就算打烊了，也不能把特地上門的客人趕回去吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"가게 밖에 취한 손님이 쓰러져 있어서 말이지. 택시까지 바래다주고 오는 길이라네.","JPN":"お店の外に酔っぱらった客が倒れていてね。タクシーに乗せてきたところだ。","ENG":"I saw one of your drunk customers sleeping outside the bar. So, I grabbed a cab for him before coming in.","TWN":"店外有個醉倒的客人，我正好送他上計程車回來。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어머, 그래서 늦은 거야? 상냥하기도 해라.","JPN":"あら、それで遅くなったの？　なんてお優しい。","ENG":"Oh, my. Is that why you're late? How sweet of you.","TWN":"哎呀，所以才這麼晚啊？你真善良呢。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 손님은 딱 한 잔만 마셨다고 하더군. 세 잔을 마시면 소원도 이룰 수 있었다고 하던데.","JPN":"あの客は1杯だけ飲んでいたらしい。3杯を飲むと願いも叶えたと言ってたが。","ENG":"I heard he only had one glass. He mentioned how his wish was going to be granted if he finished three.","TWN":"那位客人說他只喝了一杯。要是喝到三杯，就能實現願望。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"우리 가게의 전통 이벤트야. 내기에서 이긴 사람은 아직 없지만.","JPN":"このお店ならではのイベントよ。賭けで勝った人はまだいないけど。","ENG":"It's a traditional event at my bar. But no one has ever beat me.","TWN":"這是我們店的傳統，不過還沒有人贏過就是了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"소원이라. 그건 누가 이뤄주는 거지?","JPN":"願いか。それは誰が叶えてくれるのかね？","ENG":"A wish... But who grants it?","TWN":"願望……是由誰來實現呢？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"바로 나야. 왜? 관심이라도 있어?","JPN":"アタシよ。何？　興味でもあるのかしら。","ENG":"I do. Why? Are you interested?","TWN":"當然是我。怎麼？你有興趣？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"소원을 마다할 사람은 없지. 거기에 좋은 술과 내기라는 여흥까지 있다면야.","JPN":"願いを断る人はいない。それにいいお酒と賭けという余興まであるならな。","ENG":"No one will say no to a free wish. More so if it includes alcohol and the thrill of a wager.","TWN":"沒有人會拒絕願望吧？而且還有好酒和賭局這種樂趣。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"좋아. 원한다면 지금 바로 시작해볼까?","JPN":"いいわよ。よかったら今すぐ始める？","ENG":"All right. If you want, we can start right now.","TWN":"好啊。你想要的話，現在就開始？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 쉽게 기회를 줘도 괜찮은 건가?","JPN":"そう簡単にチャンスを与えてもいいのか？","ENG":"Are you sure you're all right with giving me a chance so easily?","TWN":"你這麼輕易就給我機會，真的沒問題嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"잘 생긴 사람이 취해서 망가지는 걸 보는 것도 재미거든. 난 그걸로 충분해.","JPN":"イケメンが酔っぱらってダメになる姿を見るのも面白いの。アタシはそれで十分だわ。","ENG":"It's fun to watch someone as handsome as you get drunk. That's enough for me.","TWN":"看帥哥喝醉出糗也挺有趣的，這樣我就滿足了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"향이 참 좋군. 이런 건 처음이야.","JPN":"いい香りだ。こんなものは初めてだな。","ENG":"The smell is amazing. I've never had anything like this before.","TWN":"香氣真好，第一次聞到這種味道。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그렇지? 나도 오랫동안 찾아 헤맨 향이야.","JPN":"でしょう？　アタシも結構長く探し求めてた香りなのよ。","ENG":"I know, right? It's a scent I've searched a long time for.","TWN":"對吧？這是我找了很久才找到的香氣。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 칵테일의 이름은 뭐지?","JPN":"このカクテルの名前は何だ？","ENG":"What's the name of this cocktail?","TWN":"這杯雞尾酒叫什麼？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"데몬 레이디. 내가 지었어.","JPN":"デーモンレディー。アタシがつけたわ。","ENG":"It's called Demon Lady. I named it myself.","TWN":"惡魔淑女。是我取的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"상당히 직설적인 타입이군, 그래?","JPN":"相当ストレートなタイプだな。","ENG":"You're quite the straightforward type, aren't you?","TWN":"還真直白呢，對吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"거짓말을 못하는 건 타고난 천성이거든.","JPN":"嘘がつけないのは生まれつきなの。","ENG":"Lying isn't in my nature, you see.","TWN":"我天生不會說謊。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"달콤한 향에 비해 꽤나 독한 술이군.","JPN":"甘い香りに比べてなかなか強い。","ENG":"Unlike its sweet scent, it's quite strong.","TWN":"香味這麼甜，卻是杯烈酒。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"와아- 첫 잔을 버틴 거야? 대단하네.","JPN":"わあー最初の1杯に耐えたの？　すごいわね。","ENG":"Wow... You're still good after the first glass? Impressive.","TWN":"哇—撐過第一杯了？真厲害。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"향이 참 좋은걸?","JPN":"いい香りだな？","ENG":"I love the fragrance.","TWN":"香氣真的很好耶？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"다음 잔을 마신다.","JPN":"次の1杯を飲む。","ENG":"Drink the next glass.","TWN":"我要喝下一杯。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"잠깐… 벌써 한 잔 더 마시려고?","JPN":"待って……もう飲むの？","ENG":"Wait... You're going for another glass already?","TWN":"等等……這麼快就要再來一杯？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내기 규칙에 어긋나는 건가?","JPN":"賭けのルール違反なのか？","ENG":"Oh, does it go against the rules?","TWN":"這樣有違反賭局規則嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그런 규칙은 없지만, 시간제한은 없으니 너무 무리하지 않는 편이 좋아.","JPN":"そんなルールはないけど、時間制限はないからあまり無理しない方がいいわ。","ENG":"No, there aren't any rules like that. But there also isn't a time limit, so it's best you pace yourself.","TWN":"倒也沒有這種規定。不過我們沒有時間限制，別太勉強了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"집에서도 이런 칵테일을 만들 수 있으면 좋겠는데.","JPN":"家でもこんなカクテルを作れたらいいのだが。","ENG":"I wish I could make cocktails like this at home.","TWN":"要是我也能在家裡調出這種雞尾酒就好了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"단숨에 들이킨다.","JPN":"一気に飲み干す。","ENG":"Drink it in one go.","TWN":"一口氣乾杯。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…으응? 벌써 다 마셨어?","JPN":"……うん？　もう飲み終わった？","ENG":"...Hmm? You finished all of them already?","TWN":"……咦？你已經喝完了？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"한 잔 더 부탁하지.","JPN":"もう1杯、頼む。","ENG":"Can I have another?","TWN":"請再來一杯。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"독한 술이긴 하군.","JPN":"強いお酒だな。","ENG":"It's pretty strong.","TWN":"酒還真烈。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"여섯 잔이나 마셔 놓고 할 소린 아니지 않아?","JPN":"もう6杯も飲んでおいて、そんなことを言ってるの？","ENG":"It's not very convincing after you've had six of them.","TWN":"你喝了六杯才說這種話，不太對吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"별로 취하지도 않은 것 같고. 시시해.","JPN":"あまり酔ってもいないようだし。つまらないわ。","ENG":"And you don't seem that drunk. Well, this is no fun.","TWN":"看起來也沒怎麼醉，真無聊。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 사회생활을 오래 하다보니 술을 견디는 요령도 조금씩 늘더군.","JPN":"はは。社会人として長くなると、お酒に耐えられるコツも掴めるものだ。","ENG":"Haha, I learned a thing or two about enduring alcohol after spending enough time working and meeting people.","TWN":"哈哈，在社會上打滾久了，酒量也會慢慢增加。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼 이제 소원을 말해도 되겠지?","JPN":"では、もう願いを言ってもいいのだな？","ENG":"Then, can I say my wish now?","TWN":"那我可以說願望了吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"별 수 없네. 약속은 약속이니까.","JPN":"仕方ないね。約束は約束だから。","ENG":"You leave me with no choice. A promise is a promise.","TWN":"真拿你沒辦法，約定就是約定。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"뭐든 말해봐.","JPN":"何でも言ってみて。","ENG":"What is it that you want?","TWN":"說吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 이곳에 온 목적에 대해 알려주지 않겠나?","JPN":"君がここに来た目的について教えてくれないか？","ENG":"I want to know what your purpose here is.","TWN":"能不能告訴我，你來到這裡的真正目的？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"딱히 방해할 생각은 없어. 우린 그저 예정된 결말을 지켜볼 뿐이야.","JPN":"別に邪魔するつもりはないわ。アタシたちはただ、予定された結末を見守るだけ。","ENG":"No intention of interfering. We're just here to see the preordained ending.","TWN":"我沒有要妨礙你的意思。我們只是旁觀既定的結局。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"손님이 원하는 첫번째 목적을 이룰 때까지.","JPN":"お客さんが望む最初の目的を達成するまで。","ENG":"Well, until you've achieved your first objective.","TWN":"直到客人完成第一個目的為止。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"첫번째 목적이라. 내가 그걸 이루는 것이 자네가 목격한 미래인가?","JPN":"最初の目的か。私がそれを達成するのが、君が目撃した未来なのか？","ENG":"My first objective, you say. Is that the future that you witnessed?","TWN":"第一個目的……那就是你所見到的未來嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"난 점을 재미로만 봐. 미래라는 건 결국, 그렇게 될 거라는 <color=#ffd34c>믿음</color>일 뿐이니까.","JPN":"アタシは面白半分でしか占わないわ。未来というのは結局、そうなると<color=#ffd34c>信じる</color>ことに過ぎないんだからね。","ENG":"I only do fortune-telling for fun. The future is ultimately just a <color=#ffd34c>belief</color> that it will happen.","TWN":"我只是把占卜當娛樂。所謂的未來，終究只是會變成那樣的<color=#ffd34c>信念</color>罷了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그런 건 손님이 더 잘 알지 않아?","JPN":"そんなの、お客さんのほうがもっとよくわかってるんでしょう？","ENG":"But you know that better than me, don't you?","TWN":"這一點，客人不是更清楚嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그게 단순한 믿음일 뿐이라고 해도, 동기부여가 될 만한 소재는 많을수록 좋지.","JPN":"それが単に信じることに過ぎないとしても、動機になるような素材は多ければ多いほどいい。","ENG":"Even if it's simply a belief, it's still better to have more reasons to keep you motivated.","TWN":"即便只是信念，如果能化為賦予動機的素材，當然越多越好。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"술집 미녀의 진심 어린 키스… 같은 건 동기부여로 부족한 가봐? 용사님?","JPN":"バーの美女の本気が込められたキス……とかは動機として足りないみたいね。勇者さん。","ENG":"And for you, a sincere kiss from a beautiful bartender... isn't enough motivation, is it? Hero?","TWN":"像是酒吧美女真心的一吻……這樣的動力還不夠嗎，勇者大人？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"거짓말은 못한다더니, 말장난은 잘 하는군.","JPN":"嘘はつけないと言っていたが、冗談はよく言うんだな。","ENG":"You say you can't lie, but I see you're good with jokes.","TWN":"你說不會說謊，倒是挺會玩文字遊戲的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"응? 방금 건 말장난 아닌데?","JPN":"うん？　今のは冗談じゃないわ。","ENG":"Hmm? That wasn't a joke.","TWN":"嗯？剛剛那可不是文字遊戲喔？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠, 이만 계산해도 되겠나?","JPN":"コホン。もうお会計、いいか？","ENG":"Ahem. Could I get the bill now?","TWN":"咳，那我可以結帳了嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…괜찮아. 술값은 이미 받았으니까.","JPN":"……いいわよ。飲み代はもうもらったし。","ENG":"...It's fine. I've already got my payment.","TWN":"……不用了，我已經收過酒錢了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이런. 나도 모르는 사이에 계약서라도 쓴 건가?","JPN":"おっと。知らないうちに契約書でも書いたのか？","ENG":"Oh, did I sign a contract without my knowing?","TWN":"這樣啊，我是不知不覺簽了什麼合約嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"후훗, 그 반대야. 난 손님에게 우리의 미래를 걸고 있거든.","JPN":"ふふっ、逆よ。アタシはお客さんにアタシたちの未来を預けてるの。","ENG":"Hah hah, it's the other way around. I'm betting our future on you.","TWN":"呵呵，正好相反。我可是把我們的未來押在你身上。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"진심으로 손님의 계획이 성공하길 바라고 있어.","JPN":"本気でお客さんの計画が成功することを願っているわ。","ENG":"I truly hope that your plan succeeds.","TWN":"我是真心希望你的計畫能成功。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그리고 이건 선물.","JPN":"そして、これはプレゼント。","ENG":"And this is a gift.","TWN":"還有，這是禮物。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이건…? 자네의 개인 명함이군.","JPN":"これは……？　君の個人名刺だな。","ENG":"This is...? You're personal business card.","TWN":"這是……你的個人名片？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"우리 중엔 당신의 계획을 방해하는 게 옳다고 믿는 덜떨어진 녀석들도 있거든.","JPN":"アタシたちの中ではアナタの計画を邪魔することが正しいと信じているバカなやつらもいるのよ。","ENG":"Among us, there are bigots who believe that it's in our interest to soil your plans.","TWN":"我們之中，也有些笨蛋覺得該阻止你的計畫。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그런 애들이 폐를 끼치게 되면 꼭 연락해.","JPN":"そんな子たちが迷惑をかけると、必ず連絡してちょうだい。","ENG":"If any of them bother you, give me a call.","TWN":"要是那些人來找麻煩，記得聯絡我。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"내가 잘 타일러 볼 테니까.","JPN":"アタシがたしなめてみるわ。","ENG":"I'll try to persuade them.","TWN":"我會好好勸勸他們的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};